import React, { useState, useEffect } from 'react';
import { Bell, Settings, User, ChevronDown, Moon, Sun, LogOut, BookOpen, GraduationCap } from 'lucide-react';
import Course from './Course.jsx';
import InstructorDashboard from './InstructorDashboard.jsx';
import StudentDashboard from './components/StudentDashboard.jsx';
import LoginModal from './components/LoginModal.jsx';
import LoadingSpinner from './components/LoadingSpinner.jsx';
import ErrorBoundary from './components/ErrorBoundary.jsx';
import { ToastProvider, useToast } from './components/Toast.jsx';
import { validateCourse } from './utils/validation.js';
import useCourseStore from './store/courseStore.js';
import useAuthStore from './store/authStore.js';
import dataService from './services/api.js';

const AppContent = () => {
  const [currentPage, setCurrentPage] = useState('courses');
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const { showToast } = useToast();

  const { user, isAuthenticated, logout } = useAuthStore();
  const { courses, notifications, loading, error, setCourses, addCourse, updateCourse, deleteCourse, setLoading, setError, getStats, markNotificationRead } = useCourseStore();

  const stats = getStats();

  useEffect(() => {
    if (courses.length === 0) loadDefaultCourses();
    const darkMode = localStorage.getItem('darkMode') === 'true';
    setIsDarkMode(darkMode);
    if (darkMode) document.documentElement.classList.add('dark');
  }, [courses.length]);

  const loadDefaultCourses = async () => {
    try {
      const response = await fetch('/api/courses.php', { credentials: 'include' });
      const data = await response.json();
      if (data.success) {
        setCourses(data.courses);
      } else {
        throw new Error('API failed');
      }
    } catch (error) {
      const defaultCourses = [
        {id:1,title:'Full Stack Web Development',desc:'Master HTML, CSS, JS, React, Node.js and build dynamic web apps.',level:'Intermediate',rating:'4.8',time:'8h 30m',cat:'development',instructor:'John Parker',img:'https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=400&h=200&fit=crop',price:99,enrolled:1250,progress:65},
        {id:2,title:'Machine Learning Basics',desc:'Understand algorithms, train models, and deploy ML apps with Python.',level:'Advanced',rating:'4.9',time:'10h',cat:'ai',instructor:'Dr. Aisha Khan',img:'https://images.unsplash.com/photo-1581090700227-1e37b190418e?w=400&h=200&fit=crop',price:149,enrolled:890,progress:0},
        {id:3,title:'UI/UX Design for Beginners',desc:'Learn Figma, typography, wireframing, and design psychology.',level:'Beginner',rating:'4.6',time:'6h 45m',cat:'design',instructor:'Elena Rose',img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=400&h=200&fit=crop',price:79,enrolled:2100,progress:100},
        {id:4,title:'Advanced React Development',desc:'Deep dive into React hooks, context, performance optimization, and testing.',level:'Advanced',rating:'4.9',time:'12h 15m',cat:'development',instructor:'Sarah Chen',img:'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=400&h=200&fit=crop',price:179,enrolled:756,progress:45},
        {id:5,title:'Digital Marketing Mastery',desc:'Learn SEO, social media marketing, content strategy, and analytics.',level:'Intermediate',rating:'4.7',time:'9h 20m',cat:'business',instructor:'Mike Rodriguez',img:'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=400&h=200&fit=crop',price:129,enrolled:1890,progress:78},
        {id:6,title:'Python for Data Science',desc:'Master pandas, numpy, matplotlib, and machine learning fundamentals.',level:'Intermediate',rating:'4.8',time:'11h 45m',cat:'ai',instructor:'Dr. Lisa Wang',img:'https://images.unsplash.com/photo-1526379095098-d400fd0bf935?w=400&h=200&fit=crop',price:159,enrolled:1456,progress:23},
        {id:7,title:'Mobile App Design',desc:'Create stunning mobile interfaces with modern design principles.',level:'Beginner',rating:'4.5',time:'7h 30m',cat:'design',instructor:'Alex Thompson',img:'https://images.unsplash.com/photo-1512941937669-90a1b58e7e9c?w=400&h=200&fit=crop',price:89,enrolled:2340,progress:89},
        {id:8,title:'Blockchain Development',desc:'Build decentralized applications with Ethereum, Solidity, and Web3.',level:'Advanced',rating:'4.6',time:'14h 20m',cat:'development',instructor:'David Kim',img:'https://images.unsplash.com/photo-1639762681485-074b7f938ba0?w=400&h=200&fit=crop',price:199,enrolled:567,progress:12},
        {id:9,title:'Financial Planning & Analysis',desc:'Master budgeting, forecasting, and financial modeling techniques.',level:'Intermediate',rating:'4.4',time:'8h 15m',cat:'business',instructor:'Jennifer Adams',img:'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=400&h=200&fit=crop',price:139,enrolled:1123,progress:56},
        {id:10,title:'Deep Learning with TensorFlow',desc:'Build neural networks, CNNs, and RNNs for complex AI applications.',level:'Advanced',rating:'4.9',time:'16h 30m',cat:'ai',instructor:'Prof. Robert Zhang',img:'https://images.unsplash.com/photo-1555949963-aa79dcee981c?w=400&h=200&fit=crop',price:249,enrolled:423,progress:34},
        {id:11,title:'Brand Identity Design',desc:'Create compelling brand identities, logos, and visual systems.',level:'Intermediate',rating:'4.7',time:'9h 45m',cat:'design',instructor:'Maria Garcia',img:'https://images.unsplash.com/photo-1558655146-9f40138edfeb?w=400&h=200&fit=crop',price:119,enrolled:1678,progress:67},
        {id:12,title:'Cloud Architecture with AWS',desc:'Design scalable cloud solutions using AWS services and best practices.',level:'Advanced',rating:'4.8',time:'13h 10m',cat:'development',instructor:'James Wilson',img:'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=400&h=200&fit=crop',price:189,enrolled:834,progress:41}
      ];
      setCourses(defaultCourses);
    }
  };

  const handleCourseAction = async (action, courseData, courseId) => {
    try {
      setLoading(true);
      let result;

      switch (action) {
        case 'add':
          const validation = validateCourse(courseData);
          if (!validation.isValid) throw new Error(validation.errors[0]);
          result = { ...courseData, id: Date.now(), enrolled: 0, rating: '5.0' };
          addCourse(result);
          showToast('Course created successfully!', 'success');
          break;
        case 'update':
          updateCourse(courseId, courseData);
          showToast('Course updated successfully!', 'success');
          break;
        case 'delete':
          deleteCourse(courseId);
          showToast('Course deleted successfully!', 'success');
          break;
      }

      try {
        await dataService[action === 'add' ? 'createCourse' : action === 'update' ? 'updateCourse' : 'deleteCourse'](action === 'delete' ? courseId : result || courseData);
      } catch (apiErr) {
        console.log('API sync failed, operation saved locally');
      }

      return result;
    } catch (err) {
      showToast(`Failed to ${action} course: ${err.message}`, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const handleNotificationClick = (notification) => {
    markNotificationRead(notification.id);
    setShowNotifications(false);
  };

  const handleLogout = () => {
    logout();
    setCurrentPage('courses');
    setShowUserMenu(false);
    showToast('Logged out successfully', 'info');
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-20 h-20 bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl flex items-center justify-center mx-auto mb-6">
            <span className="text-white font-bold text-2xl">R</span>
          </div>
          <h1 className="text-4xl font-bold text-gray-900 mb-4">Welcome to RiseGen</h1>
          <p className="text-gray-600 mb-8 max-w-md mx-auto">Choose your role to get started with our learning platform</p>
          <div className="space-y-4">
            <button onClick={() => setShowLoginModal(true)} className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-3 rounded-xl font-semibold hover:from-blue-700 hover:to-purple-700 transition-all block mx-auto">
              Get Started
            </button>
            <div className="text-sm text-gray-500">
              <p>Demo accounts:</p>
              <p>Student: student@example.com / password</p>
              <p>Instructor: instructor@example.com / password</p>
            </div>
          </div>
        </div>
        {showLoginModal && <LoginModal onClose={() => setShowLoginModal(false)} />}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 via-blue-50/30 to-purple-50/30">
      <nav className="glass-nav fixed w-full z-50 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center space-x-8">
              <div className="flex items-center space-x-3 group">
                <div className="w-10 h-10 bg-gradient-to-r from-blue-600 to-purple-600 rounded-xl flex items-center justify-center shadow-lg group-hover:shadow-xl transition-all duration-300 group-hover:scale-105">
                  <span className="text-white font-bold text-lg">R</span>
                </div>
                <span className="font-display text-2xl font-bold gradient-text">RiseGen</span>
              </div>

              <div className="flex space-x-2">
                <button 
                  onClick={() => setCurrentPage('courses')} 
                  className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center space-x-2 ${currentPage === 'courses' ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white shadow-lg shadow-blue-500/25 scale-105' : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50/80 hover:scale-105'}`}
                >
                  <BookOpen className="w-4 h-4" />
                  <span>Courses</span>
                  <span className="bg-white/20 text-xs px-2 py-0.5 rounded-full">{stats.totalCourses}</span>
                </button>

                {user?.role === 'student' && (
                  <button 
                    onClick={() => setCurrentPage('dashboard')} 
                    className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center space-x-2 ${currentPage === 'dashboard' ? 'bg-gradient-to-r from-green-500 to-green-600 text-white shadow-lg shadow-green-500/25 scale-105' : 'text-gray-600 hover:text-green-600 hover:bg-green-50/80 hover:scale-105'}`}
                  >
                    <User className="w-4 h-4" />
                    <span>My Learning</span>
                  </button>
                )}

                {user?.role === 'instructor' && (
                  <button 
                    onClick={() => setCurrentPage('instructor')} 
                    className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 flex items-center space-x-2 ${currentPage === 'instructor' ? 'bg-gradient-to-r from-purple-500 to-purple-600 text-white shadow-lg shadow-purple-500/25 scale-105' : 'text-gray-600 hover:text-purple-600 hover:bg-purple-50/80 hover:scale-105'}`}
                  >
                    <GraduationCap className="w-4 h-4" />
                    <span>Instructor Panel</span>
                  </button>
                )}
              </div>
            </div>

            <div className="flex items-center space-x-3">
              <button 
                onClick={() => setIsDarkMode(!isDarkMode)} 
                className="p-3 text-gray-600 hover:text-blue-600 hover:bg-blue-50/80 rounded-xl transition-all duration-300 hover:scale-110 group"
              >
                {isDarkMode ? 
                  <Sun className="w-5 h-5 group-hover:rotate-180 transition-transform duration-500" /> : 
                  <Moon className="w-5 h-5 group-hover:rotate-12 transition-transform duration-300" />
                }
              </button>

              <div className="relative">
                <button 
                  onClick={() => setShowNotifications(!showNotifications)} 
                  className="p-3 text-gray-600 hover:text-blue-600 hover:bg-blue-50/80 rounded-xl transition-all duration-300 hover:scale-110 relative group"
                >
                  <Bell className="w-5 h-5 group-hover:animate-bounce" />
                  {stats.unreadNotifications > 0 && (
                    <span className="absolute -top-1 -right-1 w-6 h-6 bg-gradient-to-r from-red-500 to-pink-500 text-white text-xs rounded-full flex items-center justify-center animate-pulse shadow-lg">
                      {stats.unreadNotifications > 9 ? '9+' : stats.unreadNotifications}
                    </span>
                  )}
                </button>

                {showNotifications && (
                  <div className="absolute right-0 mt-2 w-80 bg-white rounded-xl shadow-xl border border-gray-200 py-2 z-50">
                    <div className="px-4 py-2 border-b border-gray-100">
                      <h3 className="font-semibold text-gray-900">Notifications</h3>
                    </div>
                    <div className="max-h-64 overflow-y-auto">
                      {notifications.map(notification => (
                        <button key={notification.id} onClick={() => handleNotificationClick(notification)} className={`w-full text-left px-4 py-3 hover:bg-gray-50 border-l-4 transition-colors ${notification.unread ? 'border-blue-500 bg-blue-50/30' : 'border-transparent'}`}>
                          <p className="text-sm text-gray-900">{notification.message}</p>
                          <p className="text-xs text-gray-500 mt-1">{notification.time}</p>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              <div className="relative">
                <button onClick={() => setShowUserMenu(!showUserMenu)} className="flex items-center space-x-2 p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                  <div className="w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center">
                    <User className="w-4 h-4 text-white" />
                  </div>
                  <span className="text-sm font-medium hidden sm:block">{user?.name}</span>
                  <ChevronDown className="w-4 h-4" />
                </button>

                {showUserMenu && (
                  <div className="absolute right-0 mt-2 w-56 bg-white rounded-xl shadow-xl border border-gray-200 py-2 z-50">
                    <div className="px-4 py-2 border-b border-gray-100">
                      <p className="text-sm font-medium text-gray-900">{user?.name}</p>
                      <p className="text-xs text-gray-500 capitalize">{user?.role}</p>
                    </div>
                    <button className="w-full flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-50">
                      <Settings className="w-4 h-4 mr-3" />Settings
                    </button>
                    <hr className="my-2" />
                    <button onClick={handleLogout} className="w-full flex items-center px-4 py-2 text-sm text-red-600 hover:bg-red-50">
                      <LogOut className="w-4 h-4 mr-3" />Logout
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </nav>

      <div className="pt-16">
        {loading && <div className="flex items-center justify-center min-h-screen"><LoadingSpinner size="large" text="Loading..." /></div>}
        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mx-4 mt-4">
            <strong>Error: </strong>{error}
          </div>
        )}
        {!loading && !error && (
          <>
            {currentPage === 'courses' && <Course courses={courses} />}
            {currentPage === 'dashboard' && user?.role === 'student' && <StudentDashboard />}
            {currentPage === 'instructor' && user?.role === 'instructor' && (
              <InstructorDashboard courses={courses} onAddCourse={(data) => handleCourseAction('add', data)} onUpdateCourse={(id, data) => handleCourseAction('update', data, id)} onDeleteCourse={(id) => handleCourseAction('delete', null, id)} />
            )}
          </>
        )}
      </div>
    </div>
  );
};

const App = () => (
  <ErrorBoundary>
    <ToastProvider>
      <AppContent />
    </ToastProvider>
  </ErrorBoundary>
);

export default App;
